--
-- 触发器 `payments`
--
DELIMITER $$
CREATE TRIGGER `check_reservation_paid` AFTER INSERT ON `payments` FOR EACH ROW BEGIN
    IF NEW.type != 'recharge' AND NEW.orderId IS NOT NULL THEN
        UPDATE reservations
        SET status = 'paid'
        WHERE id = NEW.orderId AND status = 'completed';
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `update_membership_level` AFTER INSERT ON `payments` FOR EACH ROW BEGIN
    DECLARE total_spent DECIMAL(12,2);
    DECLARE new_level VARCHAR(50);

    SELECT COALESCE(SUM(amount), 0)
    INTO total_spent
    FROM payments
    WHERE customerId = NEW.customerId
      AND type IN ('vip-deduction','qr','cash','card');

    IF total_spent >= 3000 THEN
        SET new_level = 'Platinum';
    ELSEIF total_spent >= 2000 THEN
        SET new_level = 'Gold';
    ELSEIF total_spent >= 1000 THEN
        SET new_level = 'Silver';
    ELSE
        SET new_level = 'Bronze';
    END IF;

    UPDATE customers
    SET membershipLevel = new_level
    WHERE id = NEW.customerId;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `validate_payment_amount` BEFORE INSERT ON `payments` FOR EACH ROW BEGIN
    IF NEW.amount <= 0 THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Payment amount must be greater than 0';
    END IF;
END
$$
DELIMITER ;

